  return (
    <div className="container  mt-6">
      <div className="grip">
        <div className="max-w-sm">
          <Card imgSrc="https://msp.c.yimg.jp/images/v2/FUTi93tXq405grZVGgDqG5Bn3DxYLYALg8Tg4zrToQ4DpyRSzlqbexxN2MThG6duD2721QoBAnTWjL2SvYio0cr8yQ_q4-DKK9QwQ1n0dhI9QO8SklTl4afSRqiQB2lUYkIiHpoTBbnGZzdM7OGpHKCcmbKmCKR9XfgPxCtDO9msgvq5KhfwqSEGOPE-C54ooIIyKa7mScHrlgAwgAsSxNrwaiWvgUrB3EWmL9l1mi795C2yQZZcOoyAX5R3s1QeNbyBRIKWc7HwHXcj7t2f-WYzTJYAntpRQcNKO1vlSe8O1W59qBhsVuudwRqxnXEfzBHIcQmOT_Lypet5_Tx_Fy_0W9FlVWcUL3TrArT28_Gs9Xr2xLpk6jmk65QeyMQclafCaKmjFKG9UH-BzoSD1WrwXwQoodkUKQyUK1pRqWZRudjlCH5ZjIIyb6oHZScnhYgytiMGxopffKv0SpvXnl7PM6ASG0As3cAoaDrXbp539FpRcgZPt1EEqnRtK2awF3l5HBMM9yi8D7FsiHsV2iCAOVRHc9Gq0Vlve2wdvjh65LMzHdoL7BcDSd7Z0AFA/flying-popcorn-3d-glasses-film-reel-clapboard-yellow-background-cinema-movie-concept-3d_989822-1302.jpg?errorImage=false">
            <div class="bg-neutral-primary-soft block max-w-sm p-6 border border-default rounded-base shadow-xs">
              <h5 class="mt-6 mb-2 text-2xl font-semibold tracking-tight text-heading">
                Streamlining your design process today.
              </h5>

              <p class="mb-6 text-body">
                In today’s fast-paced digital landscape, fostering seamless
                collaboration among Developers and IT Operations.
              </p>
            </div>
          </Card>
        </div>
      </div>
    </div>
  );
};

export default Movies;
